//! Native exact search for Williamson sequences of order 167.
use std::{env,fs,thread};use std::sync::{Arc,Mutex};use std::sync::atomic::{AtomicBool,AtomicI64,Ordering};use std::time::{Duration,Instant,SystemTime,UNIX_EPOCH};
const N:usize=167;
#[derive(Clone)]struct State{a:[[i8;N];4],r:[i32;83],e:i64}
impl State{fn new(a:[[i8;N];4])->Self{let mut s=Self{a,r:[0;83],e:0};s.recompute();s}fn recompute(&mut self){self.r=[0;83];for d in 1..84{for k in 0..4{for i in 0..N{self.r[d-1]+=self.a[k][i]as i32*self.a[k][(i+d)%N]as i32}}}self.e=self.r.iter().map(|&x|(x as i64)*(x as i64)).sum()}fn flip_physical(&mut self,k:usize,p:usize){let old=self.a[k][p]as i32;for d in 1..84{let z=self.a[k][(p+d)%N]as i32+self.a[k][(p+N-d)%N]as i32;let delta=-2*old*z;let b=self.r[d-1]as i64;let c=b+delta as i64;self.e+=c*c-b*b;self.r[d-1]+=delta}self.a[k][p]=-self.a[k][p]}fn flip(&mut self,k:usize,g:usize){self.flip_physical(k,g);if g>0{self.flip_physical(k,N-g)}}fn score(&self,w:&[i64;83],l1:bool)->i64{let base:i64=if l1{self.r.iter().zip(w).map(|(&x,&y)|y*x.abs()as i64).sum()}else{self.r.iter().zip(w).map(|(&x,&y)|y*(x as i64)*(x as i64)).sum()};let total:i64=self.r.iter().map(|&x|x as i64).sum();base+if l1{4*total.abs()}else{total*total}}fn rows(&self)->[i32;4]{let mut z=[0;4];for k in 0..4{z[k]=self.a[k].iter().map(|&x|x as i32).sum()}z}}
#[derive(Clone,Copy)]struct Rng(u64);impl Rng{fn next(&mut self)->u64{let mut x=self.0;x^=x<<13;x^=x>>7;x^=x<<17;self.0=x;x}fn usize(&mut self,n:usize)->usize{self.next()as usize%n}fn unit(&mut self)->f64{(self.next()>>11)as f64/(1u64<<53)as f64}}
fn random(r:&mut Rng)->State{let mut a=[[1i8;N];4];for k in 0..4{for g in 0..84{let x=if r.next()&1==0{1}else{-1};a[k][g]=x;if g>0{a[k][N-g]=x}}}State::new(a)}
fn parse(path:&str)->Option<State>{let text=fs::read_to_string(path).ok()?;let start=text.find("\"sequences\"")?;let b=text[start..].as_bytes();let mut v=Vec::with_capacity(668);let(mut i,mut n)=(0,0);while i<b.len()&&n<668{if b[i]==b'-'&&i+1<b.len()&&b[i+1]==b'1'{v.push(-1);n+=1;i+=2}else if b[i]==b'1'{v.push(1);n+=1;i+=1}else{i+=1}}if n!=668{return None}let mut a=[[1i8;N];4];for k in 0..4{a[k].copy_from_slice(&v[k*N..(k+1)*N])}Some(State::new(a))}
fn make_row_valid(s:&mut State){let rows=s.rows();let mut target=rows;let mut best=i32::MAX;for a in (-31i32..=31).step_by(2){for b in (-31i32..=31).step_by(2){for c in (-31i32..=31).step_by(2){for d in (-31i32..=31).step_by(2){let z=[a,b,c,d];if a*a+b*b+c*c+d*d==668&&(0..4).all(|k|(z[k]-rows[k]).rem_euclid(4)==0){let dist=(0..4).map(|k|(z[k]-rows[k]).abs()).sum();if dist<best{best=dist;target=z}}}}}}for k in 0..4{while s.rows()[k]!=target[k]{let needed=if target[k]>s.rows()[k]{-1}else{1};let mut best_g=1;let mut score=i64::MAX;for g in 1..84{if s.a[k][g]!=needed{continue}s.flip(k,g);let z=s.score(&[1i64;83],false);s.flip(k,g);if z<score{score=z;best_g=g}}s.flip(k,best_g)}}assert_eq!(s.rows().iter().map(|x|x*x).sum::<i32>(),668);eprintln!("row-valid seed energy={} rows={:?}",s.e,s.rows())}
fn apply_move(s:&mut State,r:&mut Rng,row:bool,undo:&mut[(usize,usize);16],used:&mut usize){if row{let k=r.usize(4);let mut p=1+r.usize(83);while s.a[k][p]!=1{p=1+r.usize(83)}let mut q=1+r.usize(83);while s.a[k][q]!=-1{q=1+r.usize(83)}undo[*used]=(k,p);undo[*used+1]=(k,q);s.flip(k,p);s.flip(k,q);*used+=2}else{let x=(r.usize(4),r.usize(84));undo[*used]=x;s.flip(x.0,x.1);*used+=1}}
fn json(s:&State,solved:bool,elapsed:f64,moves:u64)->String{let seq=s.a.iter().map(|x|format!("[{}]",x.iter().map(|v|v.to_string()).collect::<Vec<_>>().join(","))).collect::<Vec<_>>().join(",");let r=s.r.iter().map(|x|x.to_string()).collect::<Vec<_>>().join(",");format!("{{\"construction\":\"Williamson sequences order 167\",\"solved\":{},\"energy\":{},\"elapsed_s\":{},\"moves\":{},\"row_sums\":{:?},\"residual\":[{}],\"sequences\":[{}]}}\n",solved,s.e,elapsed,moves,s.rows(),r,seq)}
fn update(s:&State,id:usize,start:Instant,atom:&AtomicI64,best:&Mutex<State>){let mut seen=atom.load(Ordering::Relaxed);while s.e<seen{match atom.compare_exchange_weak(seen,s.e,Ordering::SeqCst,Ordering::Relaxed){Ok(_)=>{*best.lock().unwrap()=s.clone();let _=fs::write("williamson_167_live.json",json(s,false,start.elapsed().as_secs_f64(),0));eprintln!("best energy={} worker={} elapsed_s={:.3} rows={:?}",s.e,id,start.elapsed().as_secs_f64(),s.rows());return},Err(x)=>seen=x}}}
fn worker(id:usize,end:Instant,start:Instant,atom:Arc<AtomicI64>,best:Arc<Mutex<State>>,stop:Arc<AtomicBool>,row:bool)->u64{let epoch=SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_nanos()as u64;let mut rng=Rng(epoch^(id as u64+1).wrapping_mul(0x9e3779b97f4a7c15));let mut moves=0;while Instant::now()<end&&!stop.load(Ordering::Relaxed){let mut s=best.lock().unwrap().clone();for _ in 0..rng.usize(50){let mut u=[(0usize,0usize);16];let mut n=0;apply_move(&mut s,&mut rng,row,&mut u,&mut n)}let mut w=[1i64;83];let mut stale=0;let mut local=s.e;for step in 0..300000{if step&8191==0&&(Instant::now()>=end||stop.load(Ordering::Relaxed)){break}let phase=step as f64/300000.0;let temp=(if id%3==0{1500.0}else if id%3==1{500.0}else{150.0})*(0.0005f64).powf(phase)+0.05;let l1=id%4==2;let before=s.score(&w,l1);let roll=rng.usize(1000);let count=if roll<700{1}else if roll<950{2}else{3+rng.usize(4)};let mut undo=[(0usize,0usize);16];let mut used=0;if id%4==3&&count==1{let mut best_move=[(0usize,0usize);16];let mut best_used=0;let mut score=i64::MAX;for _ in 0..64{let mut trial=[(0usize,0usize);16];let mut n=0;apply_move(&mut s,&mut rng,row,&mut trial,&mut n);let z=s.score(&w,l1);for &(k,g) in trial[..n].iter().rev(){s.flip(k,g)}if z<score{score=z;best_used=n;best_move[..n].copy_from_slice(&trial[..n])}}for &(k,g) in &best_move[..best_used]{s.flip(k,g);undo[used]=(k,g);used+=1}}else{for _ in 0..count{apply_move(&mut s,&mut rng,row,&mut undo,&mut used)}}moves+=1;let delta=s.score(&w,l1)-before;if delta>0&&rng.unit()>=(-(delta as f64)/temp).exp(){for &(k,g) in undo[..used].iter().rev(){s.flip(k,g)}}else if s.e<local{local=s.e;stale=0;update(&s,id,start,&atom,&best);if s.e==0{let mut check=s.clone();check.recompute();if check.e==0{*best.lock().unwrap()=check;stop.store(true,Ordering::SeqCst);break}}}else{stale+=1}if id%2==1&&stale>40000{for j in 0..83{if s.r[j]!=0{w[j]=(w[j]+1+(s.r[j].abs()/4)as i64).min(64)}}stale=0}else if stale>80000{for _ in 0..(12+rng.usize(30)){let mut u=[(0usize,0usize);16];let mut n=0;apply_move(&mut s,&mut rng,row,&mut u,&mut n)}stale=0}}}moves}
fn main(){let z:Vec<String>=env::args().collect();let secs=z.get(1).and_then(|x|x.parse().ok()).unwrap_or(900);let threads=z.get(2).and_then(|x|x.parse().ok()).unwrap_or(4);let row=z.get(4).map(|x|x=="row").unwrap_or(false);let mut rng=Rng(167);let mut initial=z.get(3).and_then(|p|parse(p)).unwrap_or_else(||random(&mut rng));if z.get(3).is_none(){for _ in 0..1000{let s=random(&mut rng);if s.e<initial.e{initial=s}}}if row{make_row_valid(&mut initial)}eprintln!("seed energy={} rows={:?}",initial.e,initial.rows());let start=Instant::now();let end=start+Duration::from_secs(secs);let atom=Arc::new(AtomicI64::new(initial.e));let best=Arc::new(Mutex::new(initial));let stop=Arc::new(AtomicBool::new(false));let mut hs=vec![];for id in 0..threads{let(a,b,c)=(atom.clone(),best.clone(),stop.clone());hs.push(thread::spawn(move||worker(id,end,start,a,b,c,row)))}let moves=hs.into_iter().map(|h|h.join().unwrap()).sum();let mut ans=best.lock().unwrap().clone();ans.recompute();let solved=ans.e==0;let out=if solved{"williamson_167_candidate.json"}else if row{"williamson_167_row_summary.json"}else{"williamson_167_summary.json"};fs::write(out,json(&ans,solved,start.elapsed().as_secs_f64(),moves)).unwrap();println!("result solved={} energy={} moves={} output={}",solved,ans.e,moves,out)}
